const input = $input.first().json;
const action = input.action || 'list_calendars';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

async function getCred(key) {
  const res = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.caldav-calendar&cred_key=eq.' + key + '&select=cred_value',
    headers: pgHeaders
  });
  return (res && res.length > 0) ? res[0].cred_value : null;
}

const baseUrl = await getCred('caldav_url');
const username = await getCred('caldav_username');
const password = await getCred('caldav_password');

if (!baseUrl || !username || !password) {
  return [{ json: { error: 'CalDAV credentials not configured. Use add_credential to set caldav_url, caldav_username, and caldav_password.' } }];
}

const auth = 'Basic ' + Buffer.from(username + ':' + password).toString('base64');
const calBase = baseUrl.replace(/\/$/, '') + '/calendars/' + username + '/';

async function davRequest(method, url, body, extraHeaders) {
  const opts = {
    method,
    url,
    headers: { 'Authorization': auth, ...extraHeaders },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    encoding: 'utf-8',
    json: false
  };
  if (body) opts.body = body;
  return await helpers.httpRequest(opts);
}

function extractBetween(xml, startTag, endTag) {
  const results = [];
  let pos = 0;
  while (true) {
    const s = xml.indexOf(startTag, pos);
    if (s === -1) break;
    const e = xml.indexOf(endTag, s + startTag.length);
    if (e === -1) break;
    results.push(xml.substring(s + startTag.length, e));
    pos = e + endTag.length;
  }
  return results;
}

function extractTagContent(xml, tag) {
  const patterns = [tag, tag.replace(':', '\\:')];
  for (const p of patterns) {
    const re = new RegExp('<' + p + '[^>]*>([\\s\\S]*?)</' + p + '>', 'g');
    const matches = [];
    let m;
    while ((m = re.exec(xml)) !== null) matches.push(m[1].trim());
    if (matches.length > 0) return matches;
  }
  return [];
}

function parseICSEvents(icsText) {
  const events = [];
  const blocks = extractBetween(icsText, 'BEGIN:VEVENT', 'END:VEVENT');
  for (const block of blocks) {
    const ev = {};
    const lines = block.replace(/\r\n /g, '').split(/\r?\n/);
    for (const line of lines) {
      const idx = line.indexOf(':');
      if (idx === -1) continue;
      let key = line.substring(0, idx);
      const val = line.substring(idx + 1);
      if (key.includes(';')) key = key.substring(0, key.indexOf(';'));
      if (key === 'UID') ev.uid = val;
      if (key === 'SUMMARY') ev.summary = val.replace(/\\,/g, ',').replace(/\\n/g, '\n');
      if (key === 'DESCRIPTION') ev.description = val.replace(/\\,/g, ',').replace(/\\n/g, '\n');
      if (key === 'LOCATION') ev.location = val.replace(/\\,/g, ',');
      if (key === 'DTSTART') ev.start = formatICSDate(val);
      if (key === 'DTEND') ev.end = formatICSDate(val);
      if (key === 'STATUS') ev.status = val;
    }
    if (ev.uid || ev.summary) events.push(ev);
  }
  return events;
}

function formatICSDate(val) {
  if (!val) return val;
  const clean = val.replace('Z', '');
  if (clean.length === 8) return clean.substring(0, 4) + '-' + clean.substring(4, 6) + '-' + clean.substring(6, 8);
  if (clean.length >= 15) return clean.substring(0, 4) + '-' + clean.substring(4, 6) + '-' + clean.substring(6, 8) + 'T' + clean.substring(9, 11) + ':' + clean.substring(11, 13) + ':' + clean.substring(13, 15) + (val.endsWith('Z') ? 'Z' : '');
  return val;
}

function toICSDate(iso) {
  if (!iso) return '';
  return iso.replace(/[-:]/g, '').replace(/\.\d+/, '').replace(/Z$/, '') + 'Z';
}

function buildICS(uid, summary, dtstart, dtend, description, location) {
  const now = new Date().toISOString().replace(/[-:]/g, '').replace(/\.\d+/, '');
  const lines = [
    'BEGIN:VCALENDAR', 'VERSION:2.0', 'PRODID:-//n8n-claw//CalDAV//EN',
    'BEGIN:VEVENT',
    'UID:' + uid,
    'DTSTAMP:' + now,
    'DTSTART:' + toICSDate(dtstart),
    'DTEND:' + toICSDate(dtend),
    'SUMMARY:' + (summary || '').replace(/,/g, '\\,'),
  ];
  if (description) lines.push('DESCRIPTION:' + description.replace(/,/g, '\\,').replace(/\n/g, '\\n'));
  if (location) lines.push('LOCATION:' + location.replace(/,/g, '\\,'));
  lines.push('END:VEVENT', 'END:VCALENDAR');
  return lines.join('\r\n');
}

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

// === list_calendars ===
if (action === 'list_calendars') {
  try {
    const resp = await davRequest('PROPFIND', calBase, 
      '<?xml version="1.0" encoding="utf-8"?><d:propfind xmlns:d="DAV:" xmlns:cs="http://calendarserver.org/ns/" xmlns:c="urn:ietf:params:xml:ns:caldav"><d:prop><d:displayname/><d:resourcetype/><cs:getctag/></d:prop></d:propfind>',
      { 'Depth': '1', 'Content-Type': 'application/xml; charset=utf-8' }
    );
    const body = resp.body || '';
    const hrefs = extractTagContent(body, 'd:href');
    const names = extractTagContent(body, 'd:displayname');
    const calendars = [];
    for (let i = 0; i < hrefs.length; i++) {
      const href = hrefs[i];
      if (href === calBase.replace(/https?:\/\/[^/]+/, '') || !body.includes('<cal:calendar') && !body.includes('<c:calendar') && i === 0) continue;
      const parts = href.replace(/\/$/, '').split('/');
      const slug = parts[parts.length - 1];
      if (slug === username) continue;
      calendars.push({ name: names[i] || slug, id: slug });
    }
    if (calendars.length === 0) {
      return [{ json: { result: 'No calendars found.' } }];
    }
    let result = 'Calendars:\n\n';
    for (const c of calendars) {
      result += '- ' + c.name + ' (ID: ' + c.id + ')\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list calendars: ' + err.message } }];
  }

// === list_events ===
} else if (action === 'list_events') {
  const calendar = input.calendar;
  if (!calendar) return [{ json: { error: 'Parameter "calendar" is required (calendar ID from list_calendars).' } }];

  try {
    let xmlBody = '<?xml version="1.0" encoding="utf-8"?><c:calendar-query xmlns:d="DAV:" xmlns:c="urn:ietf:params:xml:ns:caldav"><d:prop><d:getetag/><c:calendar-data/></d:prop><c:filter><c:comp-filter name="VCALENDAR"><c:comp-filter name="VEVENT">';
    if (input.start || input.end) {
      const start = input.start ? toICSDate(input.start) : '19700101T000000Z';
      const end = input.end ? toICSDate(input.end) : '20991231T235959Z';
      xmlBody += '<c:time-range start="' + start + '" end="' + end + '"/>';
    }
    xmlBody += '</c:comp-filter></c:comp-filter></c:filter></c:calendar-query>';

    const resp = await davRequest('REPORT', calBase + calendar + '/', xmlBody,
      { 'Depth': '1', 'Content-Type': 'application/xml; charset=utf-8' }
    );
    const body = resp.body || '';
    const calDataBlocks = extractTagContent(body, 'cal:calendar-data').concat(extractTagContent(body, 'c:calendar-data')).concat(extractTagContent(body, 'C:calendar-data'));
    const allEvents = [];
    for (const block of calDataBlocks) {
      const evts = parseICSEvents(block);
      allEvents.push(...evts);
    }

    if (allEvents.length === 0) {
      return [{ json: { result: 'No events found in calendar "' + calendar + '".' + (input.start ? ' (range: ' + input.start + ' to ' + (input.end || 'open') + ')' : '') } }];
    }

    allEvents.sort((a, b) => (a.start || '').localeCompare(b.start || ''));

    let result = 'Events in "' + calendar + '" (' + allEvents.length + '):\n\n';
    for (const e of allEvents.slice(0, 20)) {
      result += '- ' + (e.start || '?') + (e.end ? ' → ' + e.end : '') + ': ' + (e.summary || 'No title');
      if (e.location) result += ' @ ' + e.location;
      result += '\n  UID: ' + (e.uid || '?') + '\n';
    }
    if (allEvents.length > 20) result += '(' + (allEvents.length - 20) + ' more events not shown)';
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list events: ' + err.message } }];
  }

// === create_event ===
} else if (action === 'create_event') {
  const calendar = input.calendar;
  const title = input.title;
  const start = input.start;
  const end = input.end;
  if (!calendar || !title || !start || !end) {
    return [{ json: { error: 'Parameters required: calendar, title, start (ISO 8601), end (ISO 8601).' } }];
  }

  try {
    const uid = uuid() + '@n8n-claw';
    const ics = buildICS(uid, title, start, end, input.description, input.location);
    const eventUrl = calBase + calendar + '/' + uid + '.ics';
    const resp = await davRequest('PUT', eventUrl, ics, {
      'Content-Type': 'text/calendar; charset=utf-8',
      'If-None-Match': '*'
    });
    if (resp.statusCode >= 200 && resp.statusCode < 300) {
      return [{ json: { result: 'Event created: ' + title + ' (' + start + ' → ' + end + ')\nUID: ' + uid } }];
    }
    return [{ json: { error: 'Failed to create event. Status: ' + resp.statusCode + ' Body: ' + (resp.body || '').substring(0, 300) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create event: ' + err.message } }];
  }

// === update_event ===
} else if (action === 'update_event') {
  const calendar = input.calendar;
  const eventUid = input.event_uid;
  if (!calendar || !eventUid) {
    return [{ json: { error: 'Parameters required: calendar, event_uid. Optional: title, start, end, description, location.' } }];
  }

  try {
    const cleanUid = eventUid.replace('.ics', '');
    const eventUrl = calBase + calendar + '/' + cleanUid + '.ics';
    const getResp = await davRequest('GET', eventUrl, null, {});
    if (getResp.statusCode !== 200) {
      return [{ json: { error: 'Event not found: ' + cleanUid + ' (Status: ' + getResp.statusCode + ')' } }];
    }
    const etag = getResp.headers && (getResp.headers['etag'] || getResp.headers['ETag']);
    const existing = parseICSEvents(getResp.body || '');
    if (existing.length === 0) {
      return [{ json: { error: 'Could not parse existing event.' } }];
    }
    const ev = existing[0];
    const newTitle = input.title || ev.summary || '';
    const newStart = input.start || ev.start || '';
    const newEnd = input.end || ev.end || '';
    const newDesc = input.description !== undefined ? input.description : ev.description;
    const newLoc = input.location !== undefined ? input.location : ev.location;
    const ics = buildICS(cleanUid, newTitle, newStart, newEnd, newDesc, newLoc);
    const putHeaders = { 'Content-Type': 'text/calendar; charset=utf-8' };
    if (etag) putHeaders['If-Match'] = etag;
    const putResp = await davRequest('PUT', eventUrl, ics, putHeaders);
    if (putResp.statusCode >= 200 && putResp.statusCode < 300) {
      return [{ json: { result: 'Event updated: ' + newTitle + ' (' + newStart + ' → ' + newEnd + ')' } }];
    }
    return [{ json: { error: 'Failed to update event. Status: ' + putResp.statusCode } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update event: ' + err.message } }];
  }

// === delete_event ===
} else if (action === 'delete_event') {
  const calendar = input.calendar;
  const eventUid = input.event_uid;
  if (!calendar || !eventUid) {
    return [{ json: { error: 'Parameters required: calendar, event_uid.' } }];
  }

  try {
    const cleanUid = eventUid.replace('.ics', '');
    const eventUrl = calBase + calendar + '/' + cleanUid + '.ics';
    const resp = await davRequest('DELETE', eventUrl, null, {});
    if (resp.statusCode >= 200 && resp.statusCode < 300) {
      return [{ json: { result: 'Event deleted: ' + cleanUid } }];
    }
    return [{ json: { error: 'Failed to delete event. Status: ' + resp.statusCode + ' Body: ' + (resp.body || '').substring(0, 300) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete event: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use list_calendars, list_events, create_event, update_event, or delete_event.' } }];
}
